58	/**
59	 * Convert an Effect Schema parse {@link Result} into conform's
60	 * `{ formErrors, fieldErrors }` shape. Returns `null` on success (conform's
61	 * convention for "no errors"). Issues with no path become form-level errors;
62	 * the rest are keyed by their {@link issuePathToName conform field name}.
63	 */
64	export const formatSchemaResult = <A>(
65	  result: Result.Result<A, Issue>,
66	): FormValidationErrorInput | null => {
67	  if (Result.isSuccess(result)) return null;
68	
69	  const issues = formatter(result.failure).issues;
70	  const formErrors: string[] = [];
71	  const fieldErrors: Record<string, string[]> = {};
72	
73	  for (const issue of issues) {
74	    const name = issuePathToName(issue.path);
75	    if (name === '') {
76	      formErrors.push(issue.message);
77	    } else {
