301	/** One presence issue a struct-level predicate reports, at a field path. */
302	type PresenceIssue = {
303	  readonly path: ReadonlyArray<PropertyKey>;
304	  readonly issue: string;
305	};
306	
307	/**
308	 * The required `MessageKey` a presence-requirable LEAF emits when absent. A
309	 * `nestedGroup` (handled by {@link groupPresenceIssue}) and an `optionalText`
310	 * (never presence-required) are excluded from the input type — they have no
311	 * single required key to return.
312	 */
313	const requiredMessageOf = (
314	  field: Extract<FieldKind, { requiredMessage: MessageKey }>,
315	): string => field.requiredMessage;
316	
317	/**
318	 * The presence issue an ABSENT selected-variant `nestedGroup` surfaces: a real
319	 * key inside the group, anchored at the field the definition's `presenceAnchor`
320	 * names (registration's `extra` → `tos`, matching the registration oracle's
321	 * `['extra', 'tos']` anchor, `registration-schema.ts:274-279`), or — when no
322	 * anchor is declared — the group's FIRST presence-requirable inner field (the
323	 * back-compatible default). A selected attendee branch that omits the whole
324	 * `extra` group is an error, not a success
325	 * (`make-impossible-states-unrepresentable`); WHICH inner key carries it is
326	 * DECLARED data, not a positional coincidence (`derive-dont-sync`) — this is what
327	 * makes the engine's emitted `TranslationKey` set identical to the oracle's
328	 * (ADR 0007, plan §"identical emitted TranslationKey sets").
329	 *
330	 * A declared `presenceAnchor` that does not name a presence-requirable inner field
331	 * is ignored (fall through to first) rather than silently dropped — the
332	 * `FieldName` brand guarantees it is a safe token, but it could name a non-
333	 * presence-requirable inner field (an `optionalText`); the first presence-
334	 * requirable field is then the only meaningful anchor. An empty group (no
335	 * presence-requirable inner field) cannot anchor a key, so it imposes no group-
336	 * level presence — its own (absent) inner fields carry no requirement anyway.
337	 */
338	const groupPresenceIssue = (
339	  group: Extract<FieldKind, { _tag: 'nestedGroup' }>,
340	): PresenceIssue | undefined => {
341	  if (group.presenceAnchor !== undefined) {
342	    const anchored = group.fields.find(
343	      (inner) =>
344	        inner.name === group.presenceAnchor && isPresenceRequirableLeaf(inner),
345	    );
346	    if (anchored && isPresenceRequirableLeaf(anchored)) {
347	      return {
348	        path: [group.name, anchored.name],
349	        issue: requiredMessageOf(anchored),
350	      };
351	    }
352	  }
353	  for (const inner of group.fields) {
354	    if (!isPresenceRequirableLeaf(inner)) continue;
355	    return { path: [group.name, inner.name], issue: requiredMessageOf(inner) };
356	  }
357	  return undefined;
358	};
359	
360	/**
361	 * A leaf whose PRESENCE a variant/group can require when its branch is selected:
362	 * everything except `optionalText` (empty-allowed), an `optional: true` leaf
363	 * (checkbox / scalar — legitimately absent), and a `nestedGroup` (its own
364	 * presence is anchored by {@link groupPresenceIssue}, not a single key). The
365	 * survivors all carry a `requiredMessage`, so the narrowed type is the input to
366	 * {@link requiredMessageOf}.
367	 */
368	const isPresenceRequirableLeaf = (
369	  field: FieldKind,
370	): field is Extract<FieldKind, { requiredMessage: MessageKey }> => {
371	  if (field._tag === 'optionalText' || field._tag === 'nestedGroup') {
372	    return false;
373	  }
374	  if ('optional' in field && field.optional === true) return false;
375	  return true;
376	};
377	
378	/**
379	 * The presence requirements a discriminated `variant` imposes on the SELECTED
380	 * branch's fields — at their own paths — collected (not aborted) so a payload
381	 * missing several branch fields surfaces them all at once, exactly as the
382	 * oracle's single accumulating struct filter does
383	 * (`registration-schema.ts:239-302`). A selected branch's leaf that is absent
384	 * emits the leaf's required key at `[name]`; a selected branch's absent
385	 * `nestedGroup` emits a real key at its first inner required field
386	 * ({@link groupPresenceIssue}). An off-variant field is never demanded.
387	 */
388	const variantPresenceIssues = (
389	  variant: FormVariantSet,
390	  value: Record<string, unknown>,
391	): ReadonlyArray<PresenceIssue> => {
392	  const selected = value[variant.discriminator];
393	  const branch = variant.variants.find((v) => v.value === selected);
394	  if (!branch) return [];
395	  const issues: Array<PresenceIssue> = [];
396	  for (const field of branch.fields) {
397	    if (field._tag === 'nestedGroup') {
398	      // An `optional: true` group (registration's minors-only `parent`, the
399	      // opt-in `volunteer`) is legitimately absent — the variant never demands
400	      // it; a PRESENT one still runs its inner checks (the struct codec). A
401	      // non-optional group (the always-rendered `extra`) absent inside the
402	      // selected variant is an error anchored at its first inner required field.
403	      if (field.optional !== true && value[field.name] === undefined) {
404	        const issue = groupPresenceIssue(field);
405	        if (issue) issues.push(issue);
406	      }
407	      continue;
408	    }
409	    if (!isPresenceRequirableLeaf(field)) continue;
410	    if (value[field.name] === undefined) {
411	      issues.push({ path: [field.name], issue: requiredMessageOf(field) });
412	    }
413	  }
414	  return issues;
415	};
416	
417	// ---------------------------------------------------------------------------
418	// Cross-field rules
419	// ---------------------------------------------------------------------------
420	
421	/**
422	 * The presence requirement one `requiredWhenEquals` rule imposes: when the
423	 * `when` field's value is one of `equals`, the `target` field is required, and
424	 * an absent-OR-empty target emits `message` at the target's path. Mirrors the
425	 * `method`-gated email/phone requirement of `contact.tsx:91-109`.
426	 *
427	 * The "required" sense here is PRESENCE-and-non-emptiness, not mere
428	 * key-presence. The oracle gates `email` as `Schema.optional(Email)` where
429	 * `Email` enforces `isMinLength(1)`, so `{ method: 'email', email: '' }` is a
430	 * decode error, not a success: a visibly-blank required field must never be
431	 * representable as valid (`make-impossible-states-unrepresentable`). The
432	 * recommended modelling pairs this rule with an `optional: true` `email`/text
433	 * target (optional-at-key, non-empty-when-present), where the FIELD codec
434	 * already rejects a present `''` (and does so BEFORE this struct-level filter
435	 * runs, so no duplicate issue is reported); this predicate additionally rejects
436	 * the absent/empty target so the requirement holds even if a definition gates
437	 * an empty-permitting `optionalText` target.
438	 */
439	const rulePresenceIssue = (
440	  rule: CrossFieldRule,
441	  value: Record<string, unknown>,
442	): PresenceIssue | undefined => {
443	  const trigger = value[rule.when];
444	  const triggered =
445	    typeof trigger === 'string' && rule.equals.includes(trigger as never);
446	  const target = value[rule.target];
447	  const unsatisfied = target === undefined || target === '';
448	  return triggered && unsatisfied
449	    ? { path: [rule.target], issue: rule.message }
450	    : undefined;
451	};
452	
453	/**
454	 * The SINGLE struct-level presence filter for a definition: the variant's
455	 * selected-branch requirements plus every cross-field rule, accumulated into one
456	 * issue list. Composing one accumulating filter (rather than chaining a
457	 * `.check` per concern) matches the oracle's single struct-level
458	 * `Schema.makeFilter` and is REQUIRED for fidelity — chained `.check`s ABORT
459	 * after the first failing filter (Effect's default), so two unsatisfied rules
460	 * (the contact/volunteer `email`+`phone` pair) would surface only one. One
461	 * filter collecting all issues reproduces the oracle's "report multiple failures
462	 * at once" behaviour without depending on a non-default `errors: 'all'` decode.
463	 */
464	const makePresenceFilter = (definition: FormDefinition) =>
465	  Schema.makeFilter(
466	    (value: Record<string, unknown>) => {
467	      const issues: Array<PresenceIssue> = [];
468	      if (definition.variant) {
469	        issues.push(...variantPresenceIssues(definition.variant, value));
470	      }
471	      for (const rule of definition.rules ?? []) {
472	        const issue = rulePresenceIssue(rule, value);
473	        if (issue) issues.push(issue);
474	      }
475	      return issues.length === 0 ? undefined : issues;
476	    },
477	    { title: 'FormDefinition.presence' },
478	  );
479	
480	// ---------------------------------------------------------------------------
481	// definitionToSchema — compile a FormDefinition into a validating codec
482	// ---------------------------------------------------------------------------
483	
484	/**
485	 * Compile a `FormDefinition` into the Effect Schema codec that validates its
486	 * submissions. The common `fields` and the optional variant fields form one
487	 * `Schema.Struct`; a SINGLE struct-level presence filter
488	 * ({@link makePresenceFilter}) re-imposes the variant's selected-branch
489	 * requirements and every cross-field rule, accumulating all issues at their own
490	 * field paths. The struct's `Issue` tree feeds `formatSchemaResult` unchanged.
491	 * One accumulating filter (not a chain of `.check`s) is required so multiple
492	 * unsatisfied requirements all surface, matching the oracle's single struct
493	 * filter.
494	 */
495	export const definitionToSchema = (
496	  definition: FormDefinition,
497	): Schema.Codec<DecodedForm, Encoded> => {
498	  const fields: Record<string, Schema.Top> = buildStructFields(
499	    definition.fields,
500	  );
501	  if (definition.variant) {
502	    Object.assign(fields, buildVariantOptionalFields(definition.variant));
503	  }
504	
505	  const struct = Schema.Struct(fields).check(
506	    makePresenceFilter(definition) as never,
507	  );
508	  return struct as unknown as Schema.Codec<DecodedForm, Encoded>;
509	};
