511	/**
512	 * Decode an unknown submission payload against a `FormDefinition`. Returns a
513	 * `Result` whose failure channel is the Effect Schema `Issue` tree — paired with
514	 * `formatSchemaResult` in the generic action skeleton (Branch 6.2) to bucket
515	 * failures into conform's `{ formErrors, fieldErrors }`. Reuses `parseSchema`'s
516	 * contract (`decodeUnknownResult`) so the generated codec and the hand-written
517	 * siblings share one decode boundary.
518	 */
519	export const decodeForm = (
520	  definition: FormDefinition,
521	  payload: unknown,
522	): Result.Result<DecodedForm, Issue> =>
523	  Schema.decodeUnknownResult(definitionToSchema(definition))(payload);

