 36	const StorageOp = Schema.Literals(['get', 'put', 'head', 'list', 'delete']);
 37	type StorageOp = typeof StorageOp.Type;
 38	
 39	export class StorageError extends Schema.TaggedErrorClass<StorageError>()(
 40	  'Storage.Error',
 41	  {
 42	    key: Schema.String,
 43	    op: StorageOp,
 44	    cause: Schema.optional(Schema.Defect),
 45	  },
