 76	export interface StoredObject {
 77	  readonly stream: ReadableStream<Uint8Array>;
 78	  readonly contentType: string;
 79	  readonly size: number;
 80	}
 81	
 82	export interface ObjectHead {
 83	  readonly size: number;
 84	  readonly contentType: string;
 85	  readonly lastModified: Date;
 86	  readonly etag: string;
 87	}
 88	
 89	export interface ListedObject {
 90	  readonly key: string;
 91	  readonly size: number;
 92	  readonly lastModified: Date;
 93	}
