137	export class Service extends Context.Service<
138	  Service,
139	  {
140	    readonly get: (key: string) => Effect.Effect<StoredObject, StorageError | NotFound>;
141	    readonly put: (
142	      key: string,
143	      body: Uint8Array | string,
144	      contentType: string,
145	    ) => Effect.Effect<void, StorageError>;
146	    readonly head: (
147	      key: string,
148	    ) => Effect.Effect<Option.Option<ObjectHead>, StorageError>;
149	    readonly list: (prefix?: string) => Effect.Effect<readonly ListedObject[], StorageError>;
150	    readonly delete: (key: string) => Effect.Effect<void, StorageError>;
151	  }
