 63	    email: `booth${i}@example.com`,
 64	    phone: '123-456-7890',
 65	    type: 'exhibitor',
 66	    synopsis: 'We sell health books.',
 67	    website: 'https://example.com',
 68	    company: `Booth Co. ${i} Ltd.`,
