113	const listRegistrations = (runtime: RequestRuntime, args: RouteArgs) =>
114	  runtime.run(
115	    args,
116	    Effect.gen(function* () {
117	      const storage = yield* Storage.Service;
118	      const listed = yield* storage.list('submissions/registration/');
119	      const decode = Schema.decodeUnknownEffect(
120	        Schema.fromJsonString(submissionSchema(defaultRegistrationForm)),
121	      );
